# Next.js Patterns

## Server vs Client Components

Default to Server Components. Add `'use client'` only when you need:
- `useState`, `useEffect`, `useReducer`
- Browser APIs (`window`, `document`)
- Event listeners
- Third-party client-only libraries

```tsx
// Server Component (default) — no directive needed
async function ProductPage({ params }: { params: { id: string } }) {
  const product = await db.products.findUnique({ where: { id: params.id } });
  return <ProductDetail product={product} />;
}

// Client Component
'use client';
function AddToCart({ productId }: { productId: string }) {
  const [loading, setLoading] = useState(false);
  // ...
}
```

## Route Handlers

```ts
// app/api/products/route.ts
export async function GET(request: Request) {
  const { searchParams } = new URL(request.url);
  const q = searchParams.get('q') ?? '';
  const products = await db.products.findMany({ where: { name: { contains: q } } });
  return Response.json(products);
}

export async function POST(request: Request) {
  const body = await request.json();
  // validate with zod before DB write
  const parsed = ProductSchema.safeParse(body);
  if (!parsed.success) return Response.json({ error: parsed.error }, { status: 400 });
  const product = await db.products.create({ data: parsed.data });
  return Response.json(product, { status: 201 });
}
```

## Metadata

```ts
// Static metadata
export const metadata: Metadata = {
  title: 'Product Catalog',
  description: 'Browse all products',
};

// Dynamic metadata
export async function generateMetadata({ params }: Props): Promise<Metadata> {
  const product = await getProduct(params.id);
  return { title: product.name, description: product.description };
}
```

## Loading & Error Boundaries

```
app/products/
  page.tsx       — main page
  loading.tsx    — shown while page.tsx suspends
  error.tsx      — 'use client' error boundary
  not-found.tsx  — shown when notFound() is called
```

## Data Fetching Patterns

```ts
// Parallel fetches (preferred)
const [user, products] = await Promise.all([getUser(id), getProducts()]);

// Fetch with revalidation
const data = await fetch('/api/products', { next: { revalidate: 60 } });

// Server Action
'use server';
async function updateProduct(formData: FormData) {
  const id = formData.get('id') as string;
  await db.products.update({ where: { id }, data: { name: formData.get('name') as string } });
  revalidatePath('/products');
}
```

## Image Optimization

```tsx
import Image from 'next/image';
<Image src={product.imageUrl} alt={product.name} width={400} height={300} priority />
```

## Convention
- Route groups: `(marketing)`, `(app)` — organize without affecting URL
- Colocation: keep components, hooks, utils near the route that uses them
- `lib/` for shared utilities, `components/ui/` for reusable UI

