# React Patterns

## Custom Hooks

Extract stateful logic into hooks. Name must start with `use`.

```ts
function useLocalStorage<T>(key: string, initial: T) {
  const [value, setValue] = useState<T>(() => {
    try { return JSON.parse(localStorage.getItem(key) ?? '') as T; }
    catch { return initial; }
  });
  const set = useCallback((v: T) => {
    setValue(v);
    localStorage.setItem(key, JSON.stringify(v));
  }, [key]);
  return [value, set] as const;
}
```

## Compound Components

```tsx
const Select = ({ children, value, onChange }: SelectProps) => (
  <SelectContext.Provider value={{ value, onChange }}>
    <div className="select">{children}</div>
  </SelectContext.Provider>
);
Select.Option = function Option({ value, children }: OptionProps) {
  const ctx = useContext(SelectContext);
  return <button onClick={() => ctx.onChange(value)}>{children}</button>;
};
// Usage: <Select><Select.Option value="a">A</Select.Option></Select>
```

## Error Boundaries

```tsx
// Always use for async data-fetching components
<ErrorBoundary fallback={<ErrorFallback />}>
  <Suspense fallback={<Spinner />}>
    <AsyncDataComponent />
  </Suspense>
</ErrorBoundary>
```

## Rules
- Lift state only as high as needed
- Prefer `useReducer` over multiple `useState` for complex state
- `useMemo`/`useCallback` only after profiling shows a need
- Co-locate state with the component that owns it

