# TypeScript Strict Mode

## Discriminated Unions (prefer over inheritance)

```ts
type Result<T> =
  | { ok: true; value: T }
  | { ok: false; error: string };

function divide(a: number, b: number): Result<number> {
  if (b === 0) return { ok: false, error: 'Division by zero' };
  return { ok: true, value: a / b };
}
```

## Type Narrowing

```ts
function processInput(input: string | number | null) {
  if (input === null) return 'null';
  if (typeof input === 'string') return input.toUpperCase();
  return input.toFixed(2);
}
```

## Utility Types

```ts
type PartialUser = Partial<User>;           // all optional
type ReadonlyUser = Readonly<User>;         // all readonly
type UserPreview = Pick<User, 'id' | 'name'>;  // subset
type UserWithoutPw = Omit<User, 'password'>; // exclude
type UserOrAdmin = User | Admin;             // union
```

## Generic Constraints

```ts
function getProperty<T, K extends keyof T>(obj: T, key: K): T[K] {
  return obj[key];
}
```

## Rules
- Enable `strict: true`, `noUncheckedIndexedAccess: true`
- Avoid `any` — use `unknown` + narrowing instead
- Prefer interfaces for object shapes (better error messages)
- Use `as const` for literal arrays/objects

